modules.fpm_unpack:
`timescale 1ns/1ps
module fpm_unpack(
    input  [31:0] a,
    input  [31:0] b,
    output        a_sign,
    output [7:0]  a_exp,
    output [23:0] a_mant,
    output        b_sign,
    output [7:0]  b_exp,
    output [23:0] b_mant,
    output        a_is_nan,
    output        a_is_inf,
    output        a_is_zero,
    output        b_is_nan,
    output        b_is_inf,
    output        b_is_zero
);
    // Unpack a
    assign a_sign = a[31];
    assign a_exp  = a[30:23];
    // mantissa: implicit leading 1 for normal numbers, no implicit 1 for denormals/zero
    assign a_mant = (a[30:23] == 8'h00) ? {1'b0, a[22:0]}   // denormal or zero: no implicit 1
                                         : {1'b1, a[22:0]};  // normal: implicit 1

    assign a_is_zero = (a[30:0] == 31'h0);
    assign a_is_inf  = (a[30:23] == 8'hFF) && (a[22:0] == 23'h0);
    assign a_is_nan  = (a[30:23] == 8'hFF) && (a[22:0] != 23'h0);

    // Unpack b
    assign b_sign = b[31];
    assign b_exp  = b[30:23];
    assign b_mant = (b[30:23] == 8'h00) ? {1'b0, b[22:0]}
                                         : {1'b1, b[22:0]};

    assign b_is_zero = (b[30:0] == 31'h0);
    assign b_is_inf  = (b[30:23] == 8'hFF) && (b[22:0] == 23'h0);
    assign b_is_nan  = (b[30:23] == 8'hFF) && (b[22:0] != 23'h0);

endmodule

modules.fpm_multiply:
`timescale 1ns/1ps
module fpm_multiply(
    input         a_sign,
    input  [7:0]  a_exp,
    input  [23:0] a_mant,
    input         b_sign,
    input  [7:0]  b_exp,
    input  [23:0] b_mant,
    output        result_sign,
    output [47:0] product,
    output [9:0]  raw_exp
);
    assign result_sign = a_sign ^ b_sign;
    assign product     = a_mant * b_mant;
    assign raw_exp     = {2'b00, a_exp} + {2'b00, b_exp} - 10'd127;
endmodule

modules.fpm_normalize:
`timescale 1ns/1ps
module fpm_normalize(
    input  [47:0] product,
    input  [9:0]  raw_exp,
    output [22:0] norm_frac,
    output [9:0]  norm_exp,
    output        guard,
    output        sticky
);
    wire overflow = product[47];

    assign norm_frac = overflow ? product[46:24] : product[45:23];
    assign norm_exp  = overflow ? raw_exp + 10'd1 : raw_exp;
    assign guard     = overflow ? product[23]     : product[22];
    assign sticky    = overflow ? |product[22:0]  : |product[21:0];

endmodule

modules.fpm_round_pack:
`timescale 1ns/1ps
module fpm_round_pack(
    input         sign,
    input  [22:0] norm_frac,
    input  [9:0]  norm_exp,
    input         guard,
    input         sticky,
    output reg [31:0] result,
    output reg        overflow,
    output reg        underflow
);
    wire round_up;
    wire [23:0] rounded_frac;
    wire carry_out;
    wire [10:0] adj_exp;

    // Round-to-nearest-even: round up if guard=1 AND (sticky=1 OR lsb=1)
    assign round_up = guard & (sticky | norm_frac[0]);

    // Add rounding increment to fraction
    assign rounded_frac = {1'b0, norm_frac} + {23'b0, round_up};

    // Check if rounding caused mantissa overflow (carry out)
    assign carry_out = rounded_frac[23];

    // Adjusted exponent after rounding
    assign adj_exp = {1'b0, norm_exp} + {10'b0, carry_out};

    always @(*) begin
        overflow  = 1'b0;
        underflow = 1'b0;
        result    = 32'b0;

        // Underflow: norm_exp is zero or negative (MSB set in 10-bit signed)
        // norm_exp[9] set means it wrapped negative (two's complement)
        if (norm_exp == 10'b0 || norm_exp[9]) begin
            // Underflow: result is zero
            underflow = 1'b1;
            result = {sign, 31'b0};
        end else if (norm_exp >= 10'd255) begin
            // Overflow: result is +Infinity
            overflow = 1'b1;
            result = {sign, 8'hFF, 23'b0};
        end else begin
            // Normal case: apply rounding
            if (carry_out) begin
                // Rounding caused carry - increment exponent, fraction becomes 0
                if (adj_exp >= 11'd255) begin
                    // Overflow after rounding
                    overflow = 1'b1;
                    result = {sign, 8'hFF, 23'b0};
                end else begin
                    result = {sign, adj_exp[7:0], 23'b0};
                end
            end else begin
                result = {sign, norm_exp[7:0], rounded_frac[22:0]};
            end
        end
    end

endmodule

modules.fpm_special:
module fpm_special(
    input         a_is_nan,
    input         a_is_inf,
    input         a_is_zero,
    input         b_is_nan,
    input         b_is_inf,
    input         b_is_zero,
    input         result_sign,
    output        is_special,
    output reg [31:0] special_result
);
    // Special case: NaN input, Inf*0, or 0*Inf -> NaN
    // Inf * normal -> Inf with sign
    // 0 * normal -> zero with sign
    // normal * normal -> not special

    wire nan_result  = a_is_nan | b_is_nan | (a_is_inf & b_is_zero) | (a_is_zero & b_is_inf);
    wire inf_result  = (a_is_inf | b_is_inf) & ~nan_result;
    wire zero_result = (a_is_zero | b_is_zero) & ~nan_result & ~inf_result;

    assign is_special = nan_result | inf_result | zero_result;

    always @(*) begin
        if (nan_result)
            special_result = 32'h7FC00000; // quiet NaN
        else if (inf_result)
            special_result = {result_sign, 8'hFF, 23'h0}; // signed Inf
        else if (zero_result)
            special_result = {result_sign, 31'h0}; // signed zero
        else
            special_result = 32'h0;
    end
endmodule
